#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int qp(int a,int b)
{
	int r=1;
	wh(b)
	{
		if(b&1)r=r*a;
		a=a*a;
		b>>=1;
	}
	return r;
}
CI mo=998244353;
CI mkk=55;
CI mx=3e5+10;
int n,m;
vector<int>g[mx];
int f[mx][26],d[mx];
int s[mx][mkk];
int qpow(int a,int b)
{
	int r=1;
	a%=mo;
	wh(b)
	{
		if(b&1)r=r*a%mo;
		a=a*a%mo;
		b>>=1;
	}
	return r;
}
void dfs(int u,int fa)
{
	d[u]=d[fa]+1;f[u][0]=fa;
	FOR(i,1,50)
	{
		s[u][i]=(s[fa][i]+qpow(d[u]-1,i))%mo;
	}
	FOR(i,1,25)
	{
		f[u][i]=f[f[u][i-1]][i-1];
	}
	FOI(v,g[u])
	{
		if(v==fa)continue;
		dfs(v,u);
	}
}
int lca(int x,int y)
{
	if(d[x]<d[y])swap(x,y);
	ROF(i,25,0)
	{
		if(d[f[x][i]]>=d[y])x=f[x][i];
	}
	if(x==y)return x;
	ROF(i,25,0)
	{
		if(f[x][i]!=f[y][i])x=f[x][i],y=f[y][i];
	}
	return f[x][0];
}
signed main(void)
{
	IOS
	cin>>n;
	FOR(i,2,n)
	{
		int u,v;
		cin>>u>>v;
		g[u].pb(v);
		g[v].pb(u);
	}
	dfs(1,0);
	cin>>m;
	FOR(i,1,m)
	{
		int x,y,k;
		cin>>x>>y>>k;
        int l=lca(x,y);
    	int r=(s[x][k]+s[y][k])%mo;
    	r=(r-s[l][k]+mo)%mo;
    	r=(r-s[f[l][0]][k]+mo)%mo;
		cout<<r<<'\n';
	}
	return false;
}
